namespace Corvus.Text.Json.CodeGeneration;

/// <summary>
/// Defines what code is generated by the code generation pipeline.
/// </summary>
public enum CodeGenerationMode
{
    /// <summary>
    /// Generate only the strongly-typed C# types from the JSON Schema (default).
    /// </summary>
    TypeGeneration,

    /// <summary>
    /// Generate only a standalone schema evaluator class that performs
    /// full validation and annotation collection without generating types.
    /// </summary>
    SchemaEvaluationOnly,

    /// <summary>
    /// Generate both the strongly-typed C# types and the standalone schema evaluator.
    /// </summary>
    Both,
}